patch:
diff --git a/apps/cli/src/lib/claude-settings.ts b/apps/cli/src/lib/claude-settings.ts
index f61318b..06faf30 100644
--- a/apps/cli/src/lib/claude-settings.ts
+++ b/apps/cli/src/lib/claude-settings.ts
@@ -1,5 +1,11 @@
-import { existsSync, readFileSync, writeFileSync } from "node:fs";
-import { join } from "node:path";
+import { execSync } from "node:child_process";
+import {
+	existsSync,
+	mkdirSync,
+	readFileSync,
+	writeFileSync,
+} from "node:fs";
+import { dirname, join, resolve } from "node:path";

 const HOOK_COMMAND = "rudel hooks claude session-end";

@@ -22,8 +28,34 @@ interface ClaudeSettings {
 	[key: string]: unknown;
 }

+function findClaudeDir(): string {
+	let dir = resolve(process.cwd());
+	const root = dirname(dir) === dir ? dir : undefined;
+
+	// Walk up looking for an existing .claude directory
+	while (dir !== dirname(dir)) {
+		const candidate = join(dir, ".claude");
+		if (existsSync(candidate)) {
+			return candidate;
+		}
+		dir = dirname(dir);
+	}
+
+	// Fall back to git repo root
+	try {
+		const gitRoot = execSync("git rev-parse --show-toplevel", {
+			encoding: "utf-8",
+			stdio: ["pipe", "pipe", "pipe"],
+		}).trim();
+		return join(gitRoot, ".claude");
+	} catch {
+		// Not in a git repo — fall back to cwd
+		return join(resolve(process.cwd()), ".claude");
+	}
+}
+
 export function getClaudeSettingsPath(): string {
-	return join(process.env.HOME ?? "~", ".claude", "settings.json");
+	return join(findClaudeDir(), "settings.json");
 }

 export function readClaudeSettings(): ClaudeSettings {
@@ -35,6 +67,7 @@ export function readClaudeSettings(): ClaudeSettings {

 export function writeClaudeSettings(settings: ClaudeSettings): void {
 	const path = getClaudeSettingsPath();
+	mkdirSync(dirname(path), { recursive: true });
 	writeFileSync(path, `${JSON.stringify(settings, null, 2)}\n`);
 }
